#include <iostream>
#include <string>
#include <cmath>

using namespace std;

// Function to generate a sequence of numbers
string generateSequence(int n) {
    string sequence;
    for (int i = 1; i <= n; ++i) {
        sequence += to_string(i);
    }
    return sequence;
}

// Function to create a complex pattern
void createComplexPattern(int rows, int cols, string sequence) {
    for (int i = 0; i < rows; ++i) {
        for (int j = 0; j < cols; ++j) {
            // Calculate the position in the sequence
            int index = (i * cols + j) % sequence.length();
            cout << sequence[index];
        }
        cout << endl;
    }
}

int main() {
    int rows = 5;
    int cols = 5;
    string sequence = generateSequence(10);

    createComplexPattern(rows, cols, sequence);

    return 0;
}
```

